（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "29550a9a3a9c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "330", "s": "1118", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00164', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-111-3a1cfc18', 'sub-heelevel3-c8735cdb-05', NULL, 'essay', 'A 股份有限公司（下稱 A公司）以經營食品加工為業，共發行 1,000 萬
